var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"숲……?","JPN":"森……？","ENG":"A forest...?","TWN":"森林……？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"진짜 부자는 저택 내부에도 숲을 둘 수 있나?","JPN":"本物のお金持ちって、邸宅の内部にも森を持てるものなのか？","ENG":"Can rich people really afford to have forests inside their mansions?","TWN":"真正的有錢人連在屋裡造森林也沒問題嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 아니야…… 루시아 생각해 봐…….","JPN":"いや、違う……ルシア、考えるんだ……","ENG":"No, no... Lucia, think...","TWN":"啊，不是的……露西卡，想一想……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이건 침식파의 냄새잖아.","JPN":"これは侵食波の匂いだろ。","ENG":"This is the stench of Corruption.","TWN":"這是侵蝕波的氣味啊。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"영지에 무단으로 침입하는 사람들을 어떻게 될까?","JPN":"領地に無断侵入した人たちはどうなるでしょう？","ENG":"What happens to intruders who sneak into an estate?","TWN":"擅自闖入領地的人會怎麼樣？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"평생을 숲속에서 헤매다가 죽게 됩니다!","JPN":"一生森の中で彷徨って死にます！","ENG":"They wander the forest for the rest of their lives... until they die!","TWN":"你會一輩子在森林裡徘徊，直到死去！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"그럼 어떤 원리로 숲속을 헤매게 만들지?","JPN":"じゃあ、侵入者はどうしたら森の中を彷徨うことになるのかしら、ワンちゃん？","ENG":"Then, how can we make them wander the forest?","TWN":"那麼，究竟是用什麼原理讓人在森林中迷路的呢？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"우선, 침식파가 유입되는 환경을 만듭니다!","JPN":"まずは、侵食波が流れ込む環境を作ります！","ENG":"First, you create an environment that lets the Corruption seep in!","TWN":"首先，製造出有侵蝕波湧入的環境！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NPC_GIRL","text":{"KOREA":"그런 뒤 기괴한 소문이나 불길한 징조를 유포하면 완성입니다!","JPN":"その後、奇怪な噂や不吉な兆候を流せば完成です！","ENG":"Then, you spread eerie rumors and ominous signs... and it's complete!","TWN":"然後散佈一些奇怪的傳聞或不祥的預兆就完成了！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NPC_GIRL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"잘했어. 상으로 에그타르트 한 개~","JPN":"よくできました。ご褒美にエッグタルト1個～","ENG":"Good job. Here, have an egg tart!","TWN":"很好，獎勵你一個蛋撻～"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저택에 침식파가 유입된 거야.","JPN":"邸宅に侵食波が流れ込んだんだ。","ENG":"So the Corruption seeped into the estate...","TWN":"侵蝕波流入了屋子。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 어떻게……?","JPN":"でも、どうやって……？","ENG":"But how...?","TWN":"但是怎麼會……？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"중심부로 들어온 것 같군.","JPN":"中心部に入ったようだな。","ENG":"Looks like you've reached the core of the mansion.","TWN":"好像進入到了中心。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"형제님……? 어떻게 연락을……?","JPN":"ブラザー……？　どうやって連絡を……？","ENG":"Brother Ludwig? How did you manage to contact me?","TWN":"弟兄……？怎麼聯絡……？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"안쪽은 본래 내가 연구실로 쓰던 곳이네.","JPN":"奥は本来私が研究室として使っていたところだ。","ENG":"That area used to be my personal research lab.","TWN":"裡面原本是我用作研究室的地方。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"침식파를 연구하니, 환경에 맞는 통신 수단을 갖출 수밖에.","JPN":"侵食波を研究していたから、環境に合う通信方法を備えている。","ENG":"Since I studied Corruption rays, I had no choice but to set up a communication system suited for that environment.","TWN":"既然研究侵蝕波，就不得不配備適應環境的通訊方法。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"덤으로…… 내가 침식 증후군에 시달린 이유이기도 하네.","JPN":"ちなみに……私が侵食症候群で苦しんでいた理由でもある。","ENG":"And... well, it's also the reason I developed Corruption Syndrome.","TWN":"順便說一下……這也是我飽受侵蝕症候群折磨的原因。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하긴, 이런 환경에서 멀쩡한 게 오히려 이상하죠.","JPN":"まあ、こんな環境で何ともない方がおかしいでしょうね。","ENG":"Yeah, figures. Staying okay in this mess would be weirder.","TWN":"也是，在這種環境下還能正常才奇怪呢。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"우리 수도원은 호스피스 병동도 운영하고 있습니다.","JPN":"私共の修道院はホスピス病棟も運営しています。","ENG":"Our monastery also runs a hospice ward, by the way.","TWN":"我們修道院還有經營安寧病房。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"혹시 관심이 있으신가요?","JPN":"ご興味がおありでしょうか？","ENG":"Are you interested?","TWN":"你感興趣嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"기회가 되면 알아보도록 하겠네. 하지만 지금은 아니야.","JPN":"機会があれば調べてみるとしよう。だが、今ではない。","ENG":"Maybe someday. But not now.","TWN":"有機會的話我會去了解的，但現在還不行。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"혹시 관리인들도 침식 증후군으로 헛것을 본 건 아닐까요?","JPN":"もしかして管理人の方々も侵食症候群で幻覚を経験したのでは？","ENG":"Could it be that the caretakers were just hallucinating from the Corruption Syndrome?","TWN":"難道管理員們也是因為侵蝕症候群而產生了幻覺嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그럴지도 모르지.","JPN":"そうかもしれない。","ENG":"Possibly.","TWN":"也許吧。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"하지만 난 저택의 잠재적 위협을 확인할 의무가 있네.","JPN":"だが、私には邸宅の潜在的な脅威を確認する義務がある。","ENG":"But I have an obligation to assess all potential threats to my estate.","TWN":"但是我有義務確認屋子的潛在威脅。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};